function splitByPriority(totalSettled, components) {
  let remaining = totalSettled;
  const result = {};

  for (const { key, available } of components) {
    if (remaining <= 0) {
      result[key] = 0;
      continue;
    }

    const settled = Math.min(parseFloat(remaining).toFixed(2), parseFloat(available).toFixed(2));
    result[key] = parseFloat(parseFloat(settled).toFixed(2));
    remaining -=  parseFloat(parseFloat(settled).toFixed(2));
  }

  if (parseFloat(remaining).toFixed(2) > 0) {
    throw new Error(
      `Settlement amount ${totalSettled} exceeds available balance`
    );
  }

  return result;
}

