const validateProviderApplicationNumber = providerApplicationNumber => {
  if (!providerApplicationNumber) return false;

  // Check length (1-35 characters as per AECB spec)
  if (providerApplicationNumber.length < 1 || providerApplicationNumber.length > 35) {
    return false;
  }

  // Check allowed characters (alphanumeric, underscore, minus)
  const allowedPattern = /^[a-zA-Z0-9_-]+$/;
  if (!allowedPattern.test(providerApplicationNumber)) {
    return false;
  }

  return true;
};

