const formatEnumStrings = (enumStrings) => {
  const prefixRegex = /^(LOGISTICS_FINANCE_|TRADE_FINANCE_)/;
  const suffixRegex = /_(DEFERRED|IN_TRANSIT)$/;

  const formattedStrings = enumStrings.map(enumString => 
    enumString
      .replace(prefixRegex, '') // Remove prefix
      .replace(suffixRegex, '') // Remove suffix
      .toLowerCase() // Convert to lowercase
      .split('_') // Split by underscores
      .map(word => word.charAt(0).toUpperCase() + word.slice(1)) // Capitalize each word
      .join(' ') // Join words back with spaces
  );

  return [...new Set(formattedStrings)]; // Remove duplicates
};

