    return [];
    return await trx.select(`*`)
    .from(`tradefinance.users AS users`)
    .join(`tradefinance.organisations_users AS orgUser`, function(){
      this.on(`users.id`, `orgUser.user_id`)
    })
    .join(`tradefinance.organisations AS org`, function(){
      this.on(`org.id`, `orgUser.organisation_id`)
    })
    .whereIn(`orgUser.user_department`, userDept)
