const _insertStateTransactions = async (trx, userId, orgId, action, ownerId, ownerType, state, workflow, notes) => {
  const inputObject = [];
  ownerId = Array.isArray(ownerId) ? ownerId : [ownerId];
  ownerId.forEach(id => inputObject.push({
    user_id: userId,
    organisation_id: orgId,
    action: action,
    owner_id: id,
    owner_type: ownerType,
    state: state,
    workflow: workflow,
    notes: notes,
    created_at: new Date(Date.now())
  }));
  return await trx(`lending.state_transactions`)
  .insert(inputObject);
}

