const _addWorkFlow = async (trx, workflows, payload) => {
  if (!payload.length)
    return null;
  for(let workflow of workflows){
    payload.forEach(newRow => {
      newRow.workflow = workflow;
    })
    await trx(`lending.workflow`)
    .insert(payload)
  }

  return await _updateUserPriorityInWorkflow(trx, [lendingWorkflowType.CREDIT_ASSESSMENT], payload[payload.length-1].priority + 1,lendingUsers.LEGAL)
}

