const _deleteWorkFlow = async (trx, workflows, priorities) => {
  priorities.sort();
  if (!priorities.length)
    return null;
  const query = trx(`lending.workflow`)
  .update(`deleted_at`, new Date())
  .whereIn(`workflow`, workflows)
  .andWhereNot(`user_role`, lendingUsers.LEGAL)
  .andWhereRaw(`priority IN (${priorities})`)

  return await Promise.all([query, _updateUserPriorityInWorkflow(trx, workflows, priorities[0],lendingUsers.LEGAL)])
}

