const _getLogisticsFinancePaymentDetails = async (db, financeId) => {
  const data = await db
    .select(`*`)
    .from(`lendingfinance.payment_details`)
    .where(`finance_id`, financeId);
    let result = [];
    if (data && data.length) {
      for (const info of data) {
        let pd = { ...info, ...info[`fee_details`] };
        result.push(pd);
      }
    }
    return result;
};

