  const payload = {"actual_transaction_date":paymentDate}
  if(eventName)
    payload["event_name"] = eventName;
  return await trx('lendingfinance.finance_upcoming_transactions')
  .update(payload)
  .where(`finance_id`, financeId)
  .andWhere(`event_type`, eventType);
};

