const _getFinanceTransactionDocumentQueryForLMS = async(db,transaction_id) =>{
  return await db.select(
    `tfDocs.*`,
  ).from(`lendingfinance.finance_transactions AS finTxns`)
  .leftJoin(`lending.documents AS tfDocs`, function() {
    this.on(`finTxns.document_upload_id`, `tfDocs.document_upload_id`);
  })
  .where(`finTxns.id`, transaction_id)
  .andWhere(`tfDocs.deleted_at`, null)
  .andWhere(`finTxns.deleted_at`, null)
}

